/*========================================================
  CREAR TABLA CAT_CIUDAD
========================================================*/
BEGIN
   EXECUTE IMMEDIATE 'DROP TABLE CAT_CIUDAD CASCADE CONSTRAINTS';
EXCEPTION WHEN OTHERS THEN NULL;
END;
/

CREATE TABLE CAT_CIUDAD (
    UUID_CIUDAD VARCHAR2(36)  NOT NULL,
    UUID_ESTADO VARCHAR2(36) NOT NULL,
    DESCRIPCION VARCHAR2(50) NOT NULL,
    ESTADO NUMBER(2) NOT NULL,
    FECHA_CREACION TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL,
    CREADO_POR VARCHAR2(36) NOT NULL,
    FECHA_ACTUALIZACION TIMESTAMP,
    ACTUALIZADO_POR VARCHAR2(36),
    NOTAS VARCHAR2(100),

    CONSTRAINT PK_CAT_CIUDAD PRIMARY KEY (UUID_CIUDAD),

    CONSTRAINT FK_CAT_CIUDAD_ESTADO
        FOREIGN KEY (UUID_ESTADO)
        REFERENCES CAT_ESTADO(UUID_ESTADO),

    CONSTRAINT CK_CAT_CIUDAD_ESTADO
        CHECK (ESTADO IN (0, 99))
);

COMMENT ON TABLE CAT_CIUDAD IS 'Catálogo de ciudades';
COMMENT ON COLUMN CAT_CIUDAD.UUID_CIUDAD IS 'Identificador único UUID de la ciudad';
COMMENT ON COLUMN CAT_CIUDAD.UUID_ESTADO IS 'Referencia al estado';
COMMENT ON COLUMN CAT_CIUDAD.DESCRIPCION IS 'Nombre de la ciudad';
COMMENT ON COLUMN CAT_CIUDAD.ESTADO IS '0 = Inactivo, 99 = Activo';
COMMENT ON COLUMN CAT_CIUDAD.FECHA_CREACION IS 'Fecha de creación';
COMMENT ON COLUMN CAT_CIUDAD.CREADO_POR IS 'Usuario creador';
COMMENT ON COLUMN CAT_CIUDAD.FECHA_ACTUALIZACION IS 'Fecha de actualización';
COMMENT ON COLUMN CAT_CIUDAD.ACTUALIZADO_POR IS 'Usuario que actualizó';
COMMENT ON COLUMN CAT_CIUDAD.NOTAS IS 'Observaciones adicionales';

COMMIT;


